-- FSI_DEMO_DB.WEALTH_MANAGEMENT.CLIENTS

CREATE OR REPLACE TABLE FSI_DEMO_DB.WEALTH_MANAGEMENT.CLIENTS (

    CLIENT_ID VARCHAR(20) NOT NULL,
    FIRST_NAME VARCHAR(50),
    LAST_NAME VARCHAR(50),
    EMAIL VARCHAR(100),
    PHONE VARCHAR(20),
    DATE_OF_BIRTH DATE,
    ADDRESS_LINE1 VARCHAR(200),
    CITY VARCHAR(100),
    STATE VARCHAR(2),
    ZIP_CODE VARCHAR(10),
    COUNTRY VARCHAR(50) DEFAULT 'USA',
    CLIENT_SINCE DATE,
    ADVISOR_ID VARCHAR(20),
    CLIENT_TIER VARCHAR(30),
    TOTAL_AUM NUMBER(18,2),
    RISK_TOLERANCE VARCHAR(30),
    INVESTMENT_HORIZON VARCHAR(30),
    ACCREDITED_INVESTOR BOOLEAN DEFAULT FALSE,
    TAX_BRACKET VARCHAR(20),
    CHURN_RISK_SCORE NUMBER(5,4),
    LAST_CONTACT_DATE DATE,
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (CLIENT_ID)

);


